#include <stdio.h>
#include <stdlib.h>

int atMostK(int *arr, int n, int k) {
    int *cnt = (int *)calloc(n + 1, sizeof(int)); // values are ≤ n
    int left = 0, distinct = 0, res = 0;
    for (int right = 0; right < n; ++right) {
        if (cnt[arr[right]] == 0) distinct++;
        cnt[arr[right]]++;
        while (distinct > k) {
            cnt[arr[left]]--;
            if (cnt[arr[left]] == 0) distinct--;
            left++;
        }
        res += right - left + 1;
    }
    free(cnt);
    return res;
}

int subarraysWithKDistinct(int *arr, int n, int k) {
    return atMostK(arr, n, k) - atMostK(arr, n, k - 1);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, k; scanf("%d %d", &n, &k);
        int *arr = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        printf("%d\n", subarraysWithKDistinct(arr, n, k));
        free(arr);
    }
    return 0;
}

