#include <bits/stdc++.h>
using namespace std;

int atMostK(const vector<int>& a, int k) {
    unordered_map<int,int> cnt;
    int left = 0, distinct = 0, res = 0;
    for (int right = 0; right < (int)a.size(); ++right) {
        if (cnt[a[right]]++ == 0) ++distinct;
        while (distinct > k) {
            if (--cnt[a[left]] == 0) --distinct;
            ++left;
        }
        res += right - left + 1;
    }
    return res;
}

int subarraysWithKDistinct(const vector<int>& a, int k) {
    return atMostK(a, k) - atMostK(a, k - 1);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int n, k; cin >> n >> k;
        vector<int> a(n);
        for (int &x : a) cin >> x;
        cout << subarraysWithKDistinct(a, k) << '\n';
    }
    return 0;
}

