import java.io.*;
import java.util.*;

public class Main {
    private static int atMostK(int[] a, int k) {
        Map<Integer, Integer> cnt = new HashMap<>();
        int left = 0, distinct = 0, res = 0;
        for (int right = 0; right < a.length; ++right) {
            cnt.put(a[right], cnt.getOrDefault(a[right], 0) + 1);
            if (cnt.get(a[right]) == 1) distinct++;
            while (distinct > k) {
                cnt.put(a[left], cnt.get(a[left]) - 1);
                if (cnt.get(a[left]) == 0) distinct--;
                left++;
            }
            res += right - left + 1;
        }
        return res;
    }

    private static int subarraysWithKDistinct(int[] a, int k) {
        return atMostK(a, k) - atMostK(a, k - 1);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int k = Integer.parseInt(st.nextToken());
            int[] a = new int[n];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < n; ++i) a[i] = Integer.parseInt(st.nextToken());
            sb.append(subarraysWithKDistinct(a, k)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

