import sys
from collections import defaultdict

def at_most_k(arr, k):
    cnt = defaultdict(int)
    left = distinct = 0
    res = 0
    for right, val in enumerate(arr):
        if cnt[val] == 0:
            distinct += 1
        cnt[val] += 1
        while distinct > k:
            cnt[arr[left]] -= 1
            if cnt[arr[left]] == 0:
                distinct -= 1
            left += 1
        res += right - left + 1
    return res

def subarrays_with_k_distinct(arr, k):
    return at_most_k(arr, k) - at_most_k(arr, k - 1)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it)); k = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        out.append(str(subarrays_with_k_distinct(arr, k)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

